let map;function renderMapView(container){container.innerHTML=`\n    <div id="map" class="map-container"></div>\n    <div class="map-legend">\n      <span class="legend-item"><span class="dot red"></span> Botón de Pánico</span>\n      <span class="legend-item"><span class="dot green"></span> Normal</span>\n    </div>\n  `;setTimeout(initMap,100)}function initMap(){map=L.map("map").setView([21.8818,-102.2825],13);L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png",{attribution:"© OpenStreetMap"}).addTo(map);const panicMarker=L.marker([21.885,-102.275]).addTo(map).bindPopup("<b>BOTÓN DE PÁNICO ACTIVADO</b><br>MAC: A4:BB:6D:22:11:CC<br>14:32");panicMarker._icon.style.filter="hue-rotate(330deg)";L.marker([21.878,-102.29]).addTo(map).bindPopup("Dispositivo normal - Estadio")}